        internal void BuildString(StringBuilder builder)
        {
            if (_buffer == null)
            {
                throw new ArgumentNullException("_buffer");
            }

            int originalLimit = this.Limit;
            this.Limit = _offset + _actingBlockLength;
            builder.Append("[SeekerSpreadMessage](sbeTemplateId=");
            builder.Append(SeekerSpreadMessage.TemplateId);
            builder.Append("|sbeSchemaId=");
            builder.Append(SeekerSpreadMessage.SchemaId);
            builder.Append("|sbeSchemaVersion=");
            if (_parentMessage._actingVersion != SeekerSpreadMessage.SchemaVersion)
            {
                builder.Append(_parentMessage._actingVersion);
                builder.Append('/');
            }
            builder.Append(SeekerSpreadMessage.SchemaVersion);
            builder.Append("|sbeBlockLength=");
            if (_actingBlockLength != SeekerSpreadMessage.BlockLength)
            {
                builder.Append(_actingBlockLength);
                builder.Append('/');
            }
            builder.Append(SeekerSpreadMessage.BlockLength);
